import{_ as o,o as d,c as r,a2 as e}from"./chunks/framework.DS_HIvHc.js";const k=JSON.parse('{"title":"Cowork vs Code: 뭐가 다른가요?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cowork-vs-code.md","filePath":"guide/cowork-vs-code.md","lastUpdated":1773902007000}'),a={name:"guide/cowork-vs-code.md"};function l(i,t,s,c,n,h){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="cowork-vs-code-뭐가-다른가요" tabindex="-1">Cowork vs Code: 뭐가 다른가요? <a class="header-anchor" href="#cowork-vs-code-뭐가-다른가요" aria-label="Permalink to &quot;Cowork vs Code: 뭐가 다른가요?&quot;">​</a></h1><blockquote><p>같은 Claude인데 Cowork와 Code는 뭐가 다를까? 한눈에 비교해봅시다.</p></blockquote><h2 id="한-줄-요약" tabindex="-1">한 줄 요약 <a class="header-anchor" href="#한-줄-요약" aria-label="Permalink to &quot;한 줄 요약&quot;">​</a></h2><ul><li><strong>Cowork</strong> = 사무직을 위한 AI 동료 (GUI, 마우스 클릭)</li><li><strong>Code</strong> = 개발자를 위한 AI 코딩 파트너 (터미널, 명령어)</li></ul><p>둘 다 같은 Claude AI를 사용하지만, <strong>누가 쓰느냐</strong>와 <strong>어떻게 쓰느냐</strong>가 완전히 다릅니다.</p><h2 id="상세-비교" tabindex="-1">상세 비교 <a class="header-anchor" href="#상세-비교" aria-label="Permalink to &quot;상세 비교&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>Cowork</th><th>Code</th></tr></thead><tbody><tr><td>대상 사용자</td><td>사무직, 비개발 직군</td><td>개발자, 엔지니어</td></tr><tr><td>인터페이스</td><td>GUI (데스크탑 앱, 마우스 클릭)</td><td>CLI (터미널, 키보드 명령어)</td></tr><tr><td>주요 용도</td><td>문서 작성, 데이터 분석, 이메일, 보고서</td><td>코드 작성, 디버깅, 리팩토링, 배포</td></tr><tr><td>파일 접근 방식</td><td>내 컴퓨터 파일을 GUI로 선택</td><td>프로젝트 디렉토리에서 직접 접근</td></tr><tr><td>필요한 기술 지식</td><td>없음 — 말로 부탁하면 됨</td><td>터미널, Git 등 기본 개발 지식 필요</td></tr><tr><td>설치 방법</td><td>데스크탑 앱 다운로드 후 로그인</td><td><code>npm install -g @anthropic-ai/claude-code</code></td></tr><tr><td>작업 단위</td><td>대화 &amp; 프로젝트</td><td>코드베이스 &amp; 세션</td></tr><tr><td>플러그인/스킬</td><td>GUI에서 클릭으로 추가</td><td>슬래시 명령어(<code>/skill</code>)로 관리</td></tr><tr><td>MCP 연동</td><td>설정 화면에서 토글로 연결</td><td><code>claude mcp add</code> 명령어로 연결</td></tr><tr><td>팀 협업</td><td>프로젝트 공유, 팀 스페이스</td><td>Git 브랜치, PR 리뷰, 공유 설정 파일</td></tr><tr><td>가격</td><td>Claude Pro/Team/Enterprise 요금제</td><td>Claude Pro/Team/Enterprise 요금제 (동일)</td></tr></tbody></table><h2 id="비유로-이해하기" tabindex="-1">비유로 이해하기 <a class="header-anchor" href="#비유로-이해하기" aria-label="Permalink to &quot;비유로 이해하기&quot;">​</a></h2><ul><li><strong>Cowork = 워드프로세서</strong> — 한글이나 Word처럼 누구나 열어서 바로 쓸 수 있는 도구입니다. 버튼 누르고, 메뉴 클릭하고, 결과를 눈으로 확인합니다.</li><li><strong>Code = IDE</strong> — VS Code나 IntelliJ처럼 개발자를 위한 전문 도구입니다. 명령어를 입력하고, 코드를 읽고, 터미널에서 결과를 확인합니다.</li></ul><div class="tip custom-block"><p class="custom-block-title">핵심 차이</p><p>Cowork는 <strong>&quot;나 대신 일해줘&quot;</strong> 느낌이고, Code는 <strong>&quot;나랑 같이 코딩하자&quot;</strong> 느낌입니다. 하는 일이 다르니 도구도 다른 거예요.</p></div><h2 id="이런-분은-cowork" tabindex="-1">이런 분은 Cowork <a class="header-anchor" href="#이런-분은-cowork" aria-label="Permalink to &quot;이런 분은 Cowork&quot;">​</a></h2><ul><li>사무직, 마케터, 영업, HR, 재무, 기획 등 비개발 직군</li><li>코딩을 모르지만 AI를 업무에 활용하고 싶은 분</li><li>보고서, 이메일, 데이터 정리 등 반복 업무가 많은 분</li><li>마우스 클릭으로 편하게 쓰고 싶은 분</li></ul><h2 id="이런-분은-code" tabindex="-1">이런 분은 Code <a class="header-anchor" href="#이런-분은-code" aria-label="Permalink to &quot;이런 분은 Code&quot;">​</a></h2><ul><li>소프트웨어 개발자, 데이터 엔지니어</li><li>터미널과 Git에 익숙한 분</li><li>코드 작성, 디버깅, 리팩토링을 AI와 함께 하고 싶은 분</li><li>자동화 스크립트, CI/CD 파이프라인을 다루는 분</li></ul><h2 id="둘-다-쓰면-좋은-경우" tabindex="-1">둘 다 쓰면 좋은 경우 <a class="header-anchor" href="#둘-다-쓰면-좋은-경우" aria-label="Permalink to &quot;둘 다 쓰면 좋은 경우&quot;">​</a></h2><table tabindex="0"><thead><tr><th>역할</th><th>Code로 하는 일</th><th>Cowork로 하는 일</th></tr></thead><tbody><tr><td>IT팀 매니저</td><td>코드 리뷰, 기술 검토</td><td>주간 보고서, 팀 현황 정리</td></tr><tr><td>기술 기업 PM</td><td>기술 스펙 분석, API 문서 검토</td><td>기획서 작성, 이해관계자 커뮤니케이션</td></tr><tr><td>풀스택 1인 창업자</td><td>제품 개발, 배포 자동화</td><td>투자 IR 자료, 마케팅 콘텐츠</td></tr><tr><td>데이터 분석가</td><td>분석 코드 작성, 파이프라인 구축</td><td>분석 결과 보고서, 임원 요약</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">하나의 계정으로</p><p>Claude Pro, Team, Enterprise 요금제 하나면 Cowork와 Code 모두 사용할 수 있습니다. 별도 결제가 필요하지 않아요.</p></div><h2 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h2><h3 id="cowork-쓰다가-code로-넘어갈-수-있나요" tabindex="-1">&quot;Cowork 쓰다가 Code로 넘어갈 수 있나요?&quot; <a class="header-anchor" href="#cowork-쓰다가-code로-넘어갈-수-있나요" aria-label="Permalink to &quot;&quot;Cowork 쓰다가 Code로 넘어갈 수 있나요?&quot;&quot;">​</a></h3><p>네, 가능합니다. Cowork로 AI 활용에 익숙해진 후 개발에 관심이 생기면 Code를 추가로 사용하면 됩니다. 다만 Code는 터미널 사용이 기본이라 프로그래밍 기초 학습이 선행되면 좋습니다.</p><h3 id="code로-할-수-있는-건-cowork로도-되나요" tabindex="-1">&quot;Code로 할 수 있는 건 Cowork로도 되나요?&quot; <a class="header-anchor" href="#code로-할-수-있는-건-cowork로도-되나요" aria-label="Permalink to &quot;&quot;Code로 할 수 있는 건 Cowork로도 되나요?&quot;&quot;">​</a></h3><p>아닙니다. Code는 코드 편집, Git 커밋, 테스트 실행 등 <strong>개발 전용 기능</strong>이 있고, Cowork는 문서 작업, 데이터 정리 등 <strong>사무 업무에 최적화</strong>되어 있습니다. 각자의 영역이 다릅니다.</p><h3 id="둘-다-같은-계정으로-쓸-수-있나요" tabindex="-1">&quot;둘 다 같은 계정으로 쓸 수 있나요?&quot; <a class="header-anchor" href="#둘-다-같은-계정으로-쓸-수-있나요" aria-label="Permalink to &quot;&quot;둘 다 같은 계정으로 쓸 수 있나요?&quot;&quot;">​</a></h3><p>네. 하나의 Anthropic 계정(Claude Pro, Team, Enterprise)으로 Cowork와 Code 모두 이용할 수 있습니다. 사용량은 통합 관리되며, 요금제에 따라 한도가 달라집니다.</p><div class="warning custom-block"><p class="custom-block-title">선택이 어렵다면</p><p>개발자가 아니라면 <strong>Cowork부터 시작하세요.</strong> 이 가이드는 Cowork 사용자를 위한 가이드이니, 다음 페이지로 넘어가서 바로 시작해봅시다!</p></div>',25)])])}const C=o(a,[["render",l]]);export{k as __pageData,C as default};
